/// <summary>
/// Extension class of <c>SalesQuotationDP</c> for text block management
/// </summary>
[ExtensionOf(classStr(SalesQuotationDP))]
final class FWFTextBlockSalesQuotationDP_Extension
{
}

Method.Source:
protected SalesQuotationHeaderTmp initializeSalesQuotationHeaderTmp(CustQuotationJour _custQuotationJour, FormLetterRemarks _formLetterRemarks, CustFormletterDocument _custFormletterDocument, CustFormletterParameters _custFormletterParameters)
{
    SalesQuotationHeaderTmp salesQuotationHeaderTmpCreated = next initializeSalesQuotationHeaderTmp(_custQuotationJour, _formLetterRemarks, _custFormletterDocument, _custFormletterParameters);

    FWFTextBlockReportTextInit::newParameters(salesQuotationHeaderTmpCreated, _custQuotationJour).addTexts();

    return salesQuotationHeaderTmpCreated;
}

protected SalesQuotationDetailsTmp initializeSalesQuotationDetailsTmp(CustQuotationJour _custQuotationJour, CustQuotationTrans _custQuotationTrans, CustFormletterDocument _custFormletterDocument)
{
    SalesQuotationDetailsTmp salesQuotationDetailsTmpCreated = next initializeSalesQuotationDetailsTmp(_custQuotationJour, _custQuotationTrans, _custFormletterDocument);

    FWFTextBlockReportTextInit::newParameters(salesQuotationDetailsTmpCreated, _custQuotationTrans).addTexts();

    return salesQuotationDetailsTmpCreated;
}
